using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Filters;
using System;

namespace T2ACore;

/// <summary>
/// 鉴权标签
/// 未登录返回无权限
/// </summary>
public class TPOKAttribute : Attribute, IAuthorizationFilter
{
    /// <summary>
    /// 执行
    /// </summary>
    /// <param name="context"></param>
    public void OnAuthorization(AuthorizationFilterContext context)
    {
        var status = context.HttpContext.Items["authWebStatus"];

        if (status == null)
        {
            ReturnFail(context, "tokenUnauthorized.");
            return;
        }
        if (status.ToString() != "OK")
        {
            ReturnFail(context, "tokenUnauthorized..");
            return;
        }

        return;
    }

    private static void ReturnFail(AuthorizationFilterContext context, string inMessage)
    {
        context.Result = new JsonResult(new { Status = inMessage })
        {
            StatusCode = StatusCodes.Status401Unauthorized
        };
    }

}
